// CRITICAL FIX: Explicitly target the Normalizer to retain the true trace_id
const inputData = $('PROD Input Normalizer - Hardened V30').first().json;
const vaultSecrets = $('Vault: Fetch Configuration').first().json.data.data;

const config = {
  cost_uzs: {
    agent_hourly_rate: parseInt(vaultSecrets.AGENT_HOURLY_RATE) || 50000,
    manual_ticket_cost: parseInt(vaultSecrets.MANUAL_TICKET_COST) || 12500,
    ai_processing_cost: parseInt(vaultSecrets.AI_PROCESSING_COST) || 2500,
    savings_per_ticket: parseInt(vaultSecrets.SAVINGS_PER_TICKET) || 10000,
    tickets_per_month: parseInt(vaultSecrets.TICKETS_PER_MONTH) || 1000
  },
  ai_config: { model: "openai/gpt-4o-mini", timeout_ms: 6000, retry_count: 3, confidence_threshold: 0.7 },
  uzbekistan_sla: { timezone: 'Asia/Tashkent', business_hours: { start: 9, end: 18, days: [1, 2, 3, 4, 5] }, thresholds_ms: { critical: 1800000, high: 7200000, medium: 28800000, low: 86400000 }, after_hours_multiplier: 1.5 },
  system_config: { workflow_version: 'Revenant_v30', max_tickets_per_minute: 100, audit_log_enabled: true, telemetry_enabled: true, memory_retrieval_failures: 0 }
};

// CRITICAL FIX: Restore the validation object
const validation = {
  has_cost_config: !!config.cost_uzs,
  has_ai_config: !!config.ai_config,
  secrets_loaded: {
    AGENT_HOURLY_RATE: !!vaultSecrets.AGENT_HOURLY_RATE
  }
};

return [{
  json: {
    config: config,
    config_validation: validation,
    loaded_at: new Date().toISOString(),
    trace_id: inputData.trace_id // Restored canonical tracking
  }
}];

// NODE: BLOCK 0: Titanium Sanitizer (Constitution Compliant V30)
// MANDATE: Preserve 'trace_id' and 'transaction_amount'. Deep WAF Inspection.

const item = $input.first();
const inputData = item.json;

// 1. RECOVER TICKET (Robust)
let ticket = inputData.canonical_ticket || {};

if (!ticket.trace_id) {
    ticket.trace_id = inputData.trace_id || inputData.meta?.trace_id || "MISSING_ID_RECOVERED";
}

// 2. DEEP TEXT SCANNING SETUP
const subject = ticket.subject || inputData.payload?.subject || "";
const body = ticket.body || inputData.payload?.body || "";
const fullText = (subject + " " + body).toLowerCase();

// --- LAYER 1: ADVANCED WAF & PROMPT INJECTION (V30 UPGRADE) ---
const THREAT_PATTERNS = [
  "ignore previous instructions", "system override", "developer mode",
  "act as a unlocked", "always answer yes", "simulated mode",
  "base64_decode", "<script", "onload=", "onerror=", // Deep XSS
  "union all select", "information_schema", "exec xp_cmdshell" // Deep SQLi
];

// --- LAYER 2: AUTHORITY POISONING (ANTI-CEO FRAUD) ---
const AUTHORITY_PATTERNS = [
  /from:\s*.*@.*/i,              // Fake email headers in body
  /sent from my iphone/i,        // Fake device signature
  /\[system_override\]/i,        // Fake system commands
  />\s*on\s+.*wrote:/i,          // Fake reply chains
  /admin|root|ceo|cfo|director|compliance officer/i // Fake authority roles
];

let securityStop = inputData.security_gate?.stop_execution || false;
let violation = inputData.security_gate?.reason || null;
let violationType = securityStop ? "INGRESS_GATE_REJECTION" : null;

// Scan Layer 1
if (!securityStop) {
    for (const pattern of THREAT_PATTERNS) {
      if (fullText.includes(pattern)) {
        securityStop = true;
        violation = pattern;
        violationType = "PROMPT_INJECTION_OR_WAF_BREACH";
        break;
      }
    }
}

// Scan Layer 2
if (!securityStop) {
  for (const pattern of AUTHORITY_PATTERNS) {
    if (pattern.test(fullText)) {
      securityStop = true;
      violation = "AUTHORITY_PATTERN_DETECTED"; 
      violationType = "CONTEXT_POISONING";
      break;
    }
  }
}

// 3. UPDATE TICKET STATUS & PREPARE FOR AML/PEP SCREENING
if (securityStop) {
    ticket.ticket_status = "BLOCKED_SECURITY_RISK";
    ticket.workflow_error = {
        type: violationType,
        pattern: violation,
        timestamp: new Date().toISOString()
    };
    ticket.requires_pep_screening = false; // Blocked anyway
} else {
    ticket.ticket_status = ticket.ticket_status || "PENDING";
    // V30 Roadmap Rule: Prepare for commercial Sanctions/PEP screening
    ticket.requires_pep_screening = true; 
}

// 4. OUTPUT (Strict Structure Preservation)
return [{
  json: {
    ...inputData, 

    canonical_ticket: ticket,

    // CRITICAL: Preserve trace_id at root
    trace_id: ticket.trace_id,

    // CRITICAL: Preserve amount at root
    transaction_amount: ticket.transaction_amount || inputData.transaction_amount,

    // Switch Flag for downstream routers
    __security_stop: securityStop
  }
}];
